sed -i 's/run: g2 lint/run: |\n          dirs=$(git diff --name-only origin\/main HEAD | grep -E "^[a-zA-Z0-9_.-]+\/[a-zA-Z0-9_.-]+\/" | cut -d\/ -f1,2 | sort -u || true)\n          if [ -z "$dirs" ]; then\n            echo "No package directories modified. Linting passed."\n          else\n            exit_code=0\n            for dir in $dirs; do\n              echo "Linting $dir..."\n              g2 lint "$dir"\n            done\n          fi/' .github/workflows/pr-checks.yml
